import React from 'react';
import { StyleSheet } from 'react-native';
// 1: import fetch
import fetch from 'cross-fetch'


const url = 'https://api.example.com';
// 2: use fetch with a post request to create user profile on server, and send in an email and password as json data
export const createUserWithEmailAndPassword = async (email, password) => {
    try{
        // 3: wrap fetch request inside try catch block for error handling purpose, then set options for request method with credentials option to be 'omit' so the authentication process will not cause any error.
        await fetch(`${url}/createUser`, {
            method:'POST',
            body : JSON.stringify({email,password}), // create json object with email and password inside the body data of fetch request 
            headers:{
                Accept: 'application/json',
                'Content-Type': 'application/json'  
            },
            credentials:'omit'
        })
    }catch(error){

    }
}